{
  "summary": "This paper presents a large-scale comparative study of continual learning methods applied to multiple pre-trained language models (PLMs) across several NLP classification tasks. It demonstrates that experience replay methods outperform regularization and dynamic architecture approaches in mitigating catastrophic forgetting, with BERT identified as a robust PLM for continual learning. The study also introduces a layer-wise probing technique to analyze forgetting within PLM layers, providing novel insights into internal forgetting dynamics.",
  "strengths": [
    {
      "point": "Comprehensive benchmark combining multiple CL settings, datasets, methods, and PLMs",
      "evidence": "Evaluation includes Task-IL and Class-IL settings, three diverse NLP datasets, six CL methods, and five PLMs (BERT, ALBERT, RoBERTa, GPT2, XLNET)."
    },
    {
      "point": "Demonstration that experience replay methods (ER, DERPP) outperform regularization and dynamic architecture methods",
      "evidence": "Results show ER and DERPP achieve higher average accuracy and backward transfer across datasets and PLMs (Results, Table 3)."
    },
    {
      "point": "Novel layer-wise probing methodology revealing that forgetting affects both classifier and middle layers",
      "evidence": "Layer-wise analysis highlights fragility of classifier and specific middle layers (e.g., layer 6 in BERT), with ER better preserving representations (Proposed Method, Layer-wise Probing; Results)."
    }
  ],
  "weaknesses": [
    {
      "point": "Omission of recent NLP-specific continual learning methods limits benchmark relevance",
      "evidence": "No evaluation or discussion of adapter-based or prompt tuning CL methods widely used in NLP (e.g., AdapterFusion, prefix tuning)."
    },
    {
      "point": "Lack of ablation studies on replay buffer size, sampling strategy, and replay frequency",
      "evidence": "No sensitivity analysis on key replay parameters that affect forgetting mitigation and computational cost (Results, Table 3)."
    },
    {
      "point": "Limited dataset and task diversity restricts generalizability",
      "evidence": "Only three classification datasets are used; no evaluation on generation, language modeling, or domain adaptation tasks."
    },
    {
      "point": "Absence of statistical significance testing and multiple random seeds",
      "evidence": "Reported metrics lack confidence intervals or formal tests, raising concerns about robustness of claims (Results, Tables 3-5)."
    },
    {
      "point": "Insufficient methodological transparency and missing critical experimental details",
      "evidence": "Hyperparameter tuning protocols, training hyperparameters, random seeds, and hardware/software details are not reported (Experiments section)."
    },
    {
      "point": "Layer-wise probing method is poorly defined and lacks validation",
      "evidence": "No formal definitions, pseudocode, or validation linking probing results to downstream forgetting severity."
    },
    {
      "point": "No analysis of replay memory overhead or computational trade-offs",
      "evidence": "Memory footprint and training time impact of replay buffers are not quantified despite their practical importance."
    },
    {
      "point": "Exclusive focus on English datasets limits multilingual and low-resource generalizability",
      "evidence": "No experiments or discussion on multilingual or low-resource language continual learning."
    },
    {
      "point": "Unrealistic joint training upper bound is not contextualized",
      "evidence": "No discussion of more practical upper bounds or limitations of joint training in CL scenarios."
    },
    {
      "point": "No exploration of catastrophic forgetting in generation or sequence-to-sequence tasks",
      "evidence": "All tasks are classification; generation tasks where forgetting may differ are not studied."
    },
    {
      "point": "Use of uncommon terminology ('four veins of CL methods') reduces clarity",
      "evidence": "Phrase is used without definition or justification, potentially confusing readers."
    },
    {
      "point": "No consideration of task similarity, order effects, or curriculum learning",
      "evidence": "Task order and similarity effects on forgetting and transfer are not analyzed."
    },
    {
      "point": "Code and data release status unclear at submission",
      "evidence": "No confirmation of immediate availability, hindering reproducibility."
    },
    {
      "point": "Evaluation metrics do not integrate computational efficiency trade-offs",
      "evidence": "Accuracy and transfer metrics are reported separately from computational cost, limiting practical method selection."
    },
    {
      "point": "No investigation of other forgetting mechanisms such as gradient interference or parameter importance",
      "evidence": "Focus is solely on layer-wise representational changes without broader forgetting mechanism analysis."
    },
    {
      "point": "No analysis of how pre-training objectives or PLM architectures affect forgetting",
      "evidence": "Differences in masked vs. autoregressive pre-training or parameter sharing are not explored."
    },
    {
      "point": "Absence of qualitative examples or case studies illustrating forgetting and transfer",
      "evidence": "Only quantitative results are presented, limiting intuitive understanding."
    },
    {
      "point": "No exploration of few-shot or low-resource continual learning regimes",
      "evidence": "Experiments use standard dataset sizes without investigating data scarcity scenarios."
    },
    {
      "point": "No examination of forgetting impact on model calibration or uncertainty",
      "evidence": "Model confidence and calibration under forgetting are not studied."
    }
  ],
  "questions": [
    {
      "question": "Why do experience replay methods outperform regularization and dynamic architecture methods in PLM continual learning?",
      "motivation": "Understanding the underlying mechanisms could guide development of more effective CL algorithms tailored for PLMs."
    },
    {
      "question": "How do differences in PLM pre-training objectives and architectures influence catastrophic forgetting and transfer?",
      "motivation": "Insights here could inform design of PLM-aware continual learning strategies and model selection."
    },
    {
      "question": "What is the impact of task similarity, order, and curriculum learning on forgetting and transfer in NLP continual learning?",
      "motivation": "Addressing this could improve practical CL performance by optimizing task sequences and training curricula."
    },
    {
      "question": "How does catastrophic forgetting manifest in generation and sequence-to-sequence NLP tasks?",
      "motivation": "Extending analysis beyond classification is critical for broader applicability of CL methods in NLP."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
